unit lipdecide;

{$mode objfpc}{$H+}

interface

uses
  globals, Math;

function REALCOMPARE(A, B: real): COMPTYPE;
procedure DECIDE;

implementation

const
  EPSILON_DEFAULT = 1e-6;

function REALCOMPARE(A, B: real): COMPTYPE;
var
  diff: real;
  magA, magB: real;
  scale: real;
begin
  if A = B then
    REALCOMPARE := EQ
  else
  begin
    diff := A - B;
    if A < 0 then magA := -A else magA := A;
    if B < 0 then magB := -B else magB := B;
    if magA > magB then scale := magA else scale := magB;
    if scale < 1.0 then scale := 1.0;
    if Abs(diff) / scale < 1e-6 then
      REALCOMPARE := EQ
    else if A < B then
      REALCOMPARE := LT
    else
      REALCOMPARE := GT;
  end;
end;

function Distance(x1, y1, x2, y2: real): real;
begin
  Distance := Sqrt(Sqr(x2 - x1) + Sqr(y2 - y1));
end;

function TriangleArea(x1, y1, x2, y2, x3, y3: real): real;
begin
  TriangleArea := Abs(x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)) / 2.0;
end;

function GetQuadrant(x, y: real): integer;
begin
  if (x >= 0) and (y >= 0) then
    GetQuadrant := 1
  else if (x < 0) and (y >= 0) then
    GetQuadrant := 2
  else if (x < 0) and (y < 0) then
    GetQuadrant := 3
  else
    GetQuadrant := 4;
end;

function PointToLineDistance(px, py, x1, y1, x2, y2: real): real;
var
  dx, dy: real;
  t: real;
  closestX, closestY: real;
begin
  dx := x2 - x1;
  dy := y2 - y1;
  if (REALCOMPARE(dx, 0) = EQ) and (REALCOMPARE(dy, 0) = EQ) then
    PointToLineDistance := Distance(px, py, x1, y1)
  else
  begin
    t := ((px - x1) * dx + (py - y1) * dy) / (dx * dx + dy * dy);
    if t < 0 then t := 0
    else if t > 1 then t := 1;
    closestX := x1 + t * dx;
    closestY := y1 + t * dy;
    PointToLineDistance := Distance(px, py, closestX, closestY);
  end;
end;

function CanContainInCircle(x1, y1, x2, y2, x3, y3, radius: real): boolean;
var
  a, b, c: real;
  s, area: real;
  R: real;
  d12, d23, d31: real;
  centerToVertex: real;
begin
  d12 := Distance(x1, y1, x2, y2);
  d23 := Distance(x2, y2, x3, y3);
  d31 := Distance(x3, y3, x1, y1);

  if (REALCOMPARE(d12, 0) = EQ) and (REALCOMPARE(d23, 0) = EQ) and (REALCOMPARE(d31, 0) = EQ) then
  begin
    CanContainInCircle := REALCOMPARE(d12, radius) <> GT;
    exit;
  end;

  a := d23;
  b := d31;
  c := d12;
  s := (a + b + c) / 2.0;
  area := Sqrt(s * (s - a) * (s - b) * (s - c));

  if REALCOMPARE(area, 0) = EQ then
  begin
    if REALCOMPARE(d12, 0) = EQ then
      centerToVertex := d23 / 2.0
    else if REALCOMPARE(d23, 0) = EQ then
      centerToVertex := d31 / 2.0
    else
      centerToVertex := d12 / 2.0;
    CanContainInCircle := REALCOMPARE(centerToVertex, radius) <> GT;
    exit;
  end;

  R := (a * b * c) / (4.0 * area);
  CanContainInCircle := REALCOMPARE(R, radius) <> GT;
end;

function ComputeAngle(x1, y1, x2, y2, x3, y3: real): real;
var
  dx1, dy1, dx2, dy2: real;
  dot, mag1, mag2: real;
  cosAngle: real;
begin
  dx1 := x1 - x2;
  dy1 := y1 - y2;
  dx2 := x3 - x2;
  dy2 := y3 - y2;

  dot := dx1 * dx2 + dy1 * dy2;
  mag1 := Sqrt(dx1 * dx1 + dy1 * dy1);
  mag2 := Sqrt(dx2 * dx2 + dy2 * dy2);

  if (REALCOMPARE(mag1, 0) = EQ) or (REALCOMPARE(mag2, 0) = EQ) then
  begin
    ComputeAngle := -1.0;
    exit;
  end;

  cosAngle := dot / (mag1 * mag2);
  if cosAngle > 1.0 then cosAngle := 1.0
  else if cosAngle < -1.0 then cosAngle := -1.0;

  ComputeAngle := ArcCos(cosAngle);
end;

procedure EvaluateLIC1;
var
  i: integer;
  dist: real;
begin
  CMV[1] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + 1], Y[i + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[1] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC2;
var
  i: integer;
begin
  CMV[2] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    if not CanContainInCircle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2], PARAMETERS.RADIUS1) then
    begin
      CMV[2] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC3;
var
  i: integer;
  angle: real;
begin
  CMV[3] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    angle := ComputeAngle(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if angle >= 0 then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[3] := true;
        exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC4;
var
  i: integer;
  area: real;
begin
  CMV[4] := false;
  for i := 1 to NUMPOINTS - 2 do
  begin
    area := TriangleArea(X[i], Y[i], X[i + 1], Y[i + 1], X[i + 2], Y[i + 2]);
    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[4] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC5;
var
  i, j: integer;
  quadSet: set of 1..4;
  quadCount: integer;
begin
  CMV[5] := false;
  for i := 1 to NUMPOINTS - PARAMETERS.Q_PTS + 1 do
  begin
    quadSet := [];
    for j := 0 to PARAMETERS.Q_PTS - 1 do
      quadSet := quadSet + [GetQuadrant(X[i + j], Y[i + j])];

    quadCount := 0;
    if 1 in quadSet then Inc(quadCount);
    if 2 in quadSet then Inc(quadCount);
    if 3 in quadSet then Inc(quadCount);
    if 4 in quadSet then Inc(quadCount);

    if quadCount > PARAMETERS.QUADS then
    begin
      CMV[5] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC6;
var
  i: integer;
begin
  CMV[6] := false;
  for i := 1 to NUMPOINTS - 1 do
  begin
    if REALCOMPARE(X[i + 1] - X[i], 0) = LT then
    begin
      CMV[6] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC7;
var
  i, j: integer;
  dist: real;
  x1, y1, xN, yN: real;
begin
  CMV[7] := false;
  if NUMPOINTS < 3 then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.N_PTS + 1 do
  begin
    x1 := X[i];
    y1 := Y[i];
    xN := X[i + PARAMETERS.N_PTS - 1];
    yN := Y[i + PARAMETERS.N_PTS - 1];

    for j := i to i + PARAMETERS.N_PTS - 1 do
    begin
      dist := PointToLineDistance(X[j], Y[j], x1, y1, xN, yN);
      if REALCOMPARE(dist, PARAMETERS.DIST) = GT then
      begin
        CMV[7] := true;
        exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC8;
var
  i: integer;
  dist: real;
begin
  CMV[8] := false;
  if NUMPOINTS < 3 then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
    begin
      CMV[8] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC9;
var
  i: integer;
begin
  CMV[9] := false;
  if NUMPOINTS < 5 then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if not CanContainInCircle(
      X[i], Y[i],
      X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
      X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
      PARAMETERS.RADIUS1) then
    begin
      CMV[9] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC10;
var
  i: integer;
  angle: real;
begin
  CMV[10] := false;
  if NUMPOINTS < 5 then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.C_PTS - PARAMETERS.D_PTS - 2 do
  begin
    angle := ComputeAngle(
      X[i], Y[i],
      X[i + PARAMETERS.C_PTS + 1], Y[i + PARAMETERS.C_PTS + 1],
      X[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2], Y[i + PARAMETERS.C_PTS + PARAMETERS.D_PTS + 2]);

    if angle >= 0 then
    begin
      if (REALCOMPARE(angle, PI - PARAMETERS.EPSILON) = LT) or
         (REALCOMPARE(angle, PI + PARAMETERS.EPSILON) = GT) then
      begin
        CMV[10] := true;
        exit;
      end;
    end;
  end;
end;

procedure EvaluateLIC11;
var
  i: integer;
  area: real;
begin
  CMV[11] := false;
  if NUMPOINTS < 5 then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    area := TriangleArea(
      X[i], Y[i],
      X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
      X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);

    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
    begin
      CMV[11] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC12;
var
  i: integer;
begin
  CMV[12] := false;
  if NUMPOINTS < 3 then exit;

  for i := 1 to NUMPOINTS - PARAMETERS.G_PTS - 1 do
  begin
    if REALCOMPARE(X[i + PARAMETERS.G_PTS + 1] - X[i], 0) = LT then
    begin
      CMV[12] := true;
      exit;
    end;
  end;
end;

procedure EvaluateLIC13;
var
  i: integer;
  dist: real;
  hasGreater, hasLess: boolean;
begin
  CMV[13] := false;
  if NUMPOINTS < 3 then exit;

  hasGreater := false;
  hasLess := false;

  for i := 1 to NUMPOINTS - PARAMETERS.K_PTS - 1 do
  begin
    dist := Distance(X[i], Y[i], X[i + PARAMETERS.K_PTS + 1], Y[i + PARAMETERS.K_PTS + 1]);
    if REALCOMPARE(dist, PARAMETERS.LENGTH1) = GT then
      hasGreater := true;
    if REALCOMPARE(dist, PARAMETERS.LENGTH2) = LT then
      hasLess := true;
  end;

  CMV[13] := hasGreater and hasLess;
end;

procedure EvaluateLIC14;
var
  i: integer;
  cannotContain, canContain: boolean;
begin
  CMV[14] := false;
  if NUMPOINTS < 5 then exit;

  cannotContain := false;
  canContain := false;

  for i := 1 to NUMPOINTS - PARAMETERS.A_PTS - PARAMETERS.B_PTS - 2 do
  begin
    if not CanContainInCircle(
      X[i], Y[i],
      X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
      X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
      PARAMETERS.RADIUS1) then
      cannotContain := true;

    if CanContainInCircle(
      X[i], Y[i],
      X[i + PARAMETERS.A_PTS + 1], Y[i + PARAMETERS.A_PTS + 1],
      X[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2], Y[i + PARAMETERS.A_PTS + PARAMETERS.B_PTS + 2],
      PARAMETERS.RADIUS2) then
      canContain := true;
  end;

  CMV[14] := cannotContain and canContain;
end;

procedure EvaluateLIC15;
var
  i: integer;
  area: real;
  hasGreater, hasLess: boolean;
begin
  CMV[15] := false;
  if NUMPOINTS < 5 then exit;

  hasGreater := false;
  hasLess := false;

  for i := 1 to NUMPOINTS - PARAMETERS.E_PTS - PARAMETERS.F_PTS - 2 do
  begin
    area := TriangleArea(
      X[i], Y[i],
      X[i + PARAMETERS.E_PTS + 1], Y[i + PARAMETERS.E_PTS + 1],
      X[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2], Y[i + PARAMETERS.E_PTS + PARAMETERS.F_PTS + 2]);

    if REALCOMPARE(area, PARAMETERS.AREA1) = GT then
      hasGreater := true;
    if REALCOMPARE(area, PARAMETERS.AREA2) = LT then
      hasLess := true;
  end;

  CMV[15] := hasGreater and hasLess;
end;

procedure ComputePUM;
var
  i, j: integer;
begin
  for i := 1 to 15 do
  begin
    for j := 1 to 15 do
    begin
      if i = j then
        PUM[i, j] := true
      else
      begin
        case LCM[i, j] of
          NOTUSED:
            PUM[i, j] := true;
          ANDD:
            PUM[i, j] := CMV[i] and CMV[j];
          ORR:
            PUM[i, j] := CMV[i] or CMV[j];
        end;
      end;
    end;
  end;
end;

procedure ComputeFUV;
var
  i, j: integer;
  allTrue: boolean;
begin
  for i := 1 to 15 do
  begin
    if not PUM[i, i] then
      FUV[i] := true
    else
    begin
      allTrue := true;
      for j := 1 to 15 do
      begin
        if not PUM[i, j] then
        begin
          allTrue := false;
          break;
        end;
      end;
      FUV[i] := allTrue;
    end;
  end;
end;

procedure DECIDE;
var
  i: integer;
begin
  EvaluateLIC1;
  EvaluateLIC2;
  EvaluateLIC3;
  EvaluateLIC4;
  EvaluateLIC5;
  EvaluateLIC6;
  EvaluateLIC7;
  EvaluateLIC8;
  EvaluateLIC9;
  EvaluateLIC10;
  EvaluateLIC11;
  EvaluateLIC12;
  EvaluateLIC13;
  EvaluateLIC14;
  EvaluateLIC15;

  ComputePUM;
  ComputeFUV;

  LAUNCH := true;
  for i := 1 to 15 do
  begin
    if not FUV[i] then
    begin
      LAUNCH := false;
      exit;
    end;
  end;
end;

end.
